import { orderBy, unionBy, uniqueId } from 'lodash';
import { getPropDefs } from './utils';
export default class PluginManager {
    constructor({ name, componentOptions, plugin }) {
        this.name = ''; // 组件名称
        this.key = '';
        this.valid = true;
        this.plugins = [];
        this.getPluginSetup = (isDesigner) => {
            const pluginSetups = this.plugins.filter((op) => {
                if (!op || typeof op.setup !== 'function') {
                    return false;
                }
                if (!isDesigner && op.onlyUseIDE) {
                    return false;
                }
                return true;
            }).map((op) => op.setup);
            return pluginSetups;
        };
        this.getPluginPropKeys = (propKeys) => {
            const keys = [...propKeys];
            const ps = this.plugins.map((op) => (op.props || [])).flat();
            ps.forEach((k) => {
                if (keys.indexOf(k) === -1) {
                    keys.push(k);
                }
            });
            return keys;
        };
        if (!componentOptions) {
            this.valid = false;
            return;
        }
        this.name = name || componentOptions.name;
        this.key = `${this.name}__HOC_${uniqueId()}`;
        this.baseProps = getPropDefs(componentOptions);
        this.basePropKeys = this.baseProps.map((p) => p.name);
        this.setPlugin(plugin);
    }
    setPlugin(plugin) {
        const pluginArray = this.plugins.concat(Object.keys(plugin).map((name) => (Object.assign({ order: 4, name }, plugin[name]))));
        const sortPlugin = orderBy(pluginArray, ['order'], ['asc']);
        const unionPlugin = unionBy(sortPlugin, 'name');
        this.plugins = unionPlugin;
        this.allPropKeys = this.getPluginPropKeys(this.basePropKeys);
    }
}
